1335:     static String niceMemoryUnits(long bytes) {
1336:         long value = bytes;
1337:         int i = 0;
1338:         while (value != 0 && i < 4) {
1339:             if (value % 1024L == 0) {
1340:                 value /= 1024L;
1341:                 i++;
1342:             } else {
1343:                 break;
1344:             }
1345:         }
1346:         String resultFormat = " (" + value + " %s" + (value == 1 ? ")" : "s)");
1347:         switch (i) {
1348:             case 1:
1349:                 return String.format(resultFormat, "kibibyte");
1350:             case 2:
1351:                 return String.format(resultFormat, "mebibyte");
1352:             case 3:
1353:                 return String.format(resultFormat, "gibibyte");
1354:             case 4:
1355:                 return String.format(resultFormat, "tebibyte");
1356:             default:
1357:                 return "";
1358:         }
1359:     }
