1361:     static String niceTimeUnits(long millis) {
1362:         long value = millis;
1363:         long[] divisors = {1000, 60, 60, 24};
1364:         String[] units = {"second", "minute", "hour", "day"};
1365:         int i = 0;
1366:         while (value != 0 && i < 4) {
1367:             if (value % divisors[i] == 0) {
1368:                 value /= divisors[i];
1369:                 i++;
1370:             } else {
1371:                 break;
1372:             }
1373:         }
1374:         if (i > 0) {
1375:             return " (" + value + " " + units[i - 1] + (value > 1 ? "s)" : ")");
1376:         }
1377:         return "";
1378:     }
